        finishReasonPath: "",
        finishMessagePath: "",
        streamFinishReasonPath: "",
        streamFinishMessagePath: "",
        wrapsOptionsIn: "",
        safetySettingsWirePath: "",
        modelInBody: true,
        errorMessagePath: "error.message",
        errorTypePath: "error.type",
        accessKeyEnvVar: "",
        secretKeyEnvVar: "",
        sessionTokenEnvVar: "",
        regionEnvVar: "",
        serviceName: ""
    ),
]

private let providerSpecByName: [ProviderName: ProviderSpec] =
    Dictionary(uniqueKeysWithValues: providerSpecs.map { ($0.name, $0) })

/// Look up the internal wire spec for a provider identity.
func providerConfig(_ name: ProviderName) -> ProviderSpec {
    guard let spec = providerSpecByName[name] else {
        preconditionFailure("provider config missing from generated registry")
    }
    return spec
}
